import type React from "react";
import type { PropsWithChildren } from "react";
import {
  createContext,
  useContext,
  useEffect,
  useState,
  useSyncExternalStore,
} from "react";

import type { Toaster } from "@/components/toaster/toaster-impl";
import {
  clearFirstToaster,
  setFirstToaster,
  ToasterImpl,
} from "@/components/toaster/toaster-impl";

import { Toast } from "./toast";

const toasterContext = createContext<Toaster | null>(null);

const { Provider: ToasterProvider } = toasterContext;

export { Toaster };

export function useToaster(): Toaster {
  return useContext(toasterContext) as Toaster;
}

function useToasts(): ToasterImpl["toasts"] {
  const toaster = useToaster() as ToasterImpl;
  return useSyncExternalStore(
    (l) => toaster.subscribe(l),
    () => toaster.toasts,
    () => [],
  );
}

function ToastArea(): React.ReactElement {
  const toasts = useToasts();
  const toaster = useToaster() as ToasterImpl;
  return (
    <span className="pointer-events-none fixed inset-0 z-[60] mx-auto my-2 flex max-w-[560px] flex-col items-center justify-start md:pb-5">
      {toasts
        .filter((toast) => toast.isShown !== false)
        .map(({ id, ...rest }) => (
          <Toast key={id} {...rest} onRemove={() => toaster.removeToast(id)} />
        ))}
    </span>
  );
}

export function ToastManager({
  children,
}: PropsWithChildren): React.ReactElement {
  const [manager] = useState(() => new ToasterImpl());
  useEffect(() => {
    setFirstToaster(manager);
    return (): void => {
      clearFirstToaster(manager);
    };
  }, [manager]);
  return (
    <ToasterProvider value={manager}>
      {children}
      <ToastArea />
    </ToasterProvider>
  );
}
