import clsx from "clsx";
import { useCallback, useEffect, useRef, useState } from "react";

import AlertIcon from "@/icons/alert.svg";
import CheckCircleIcon from "@/icons/check-circle.svg";
import XCircleFilledIcon from "@/icons/x-circle.svg";

import { Alert } from "./alert";
// https://github.com/openai/openai/blob/master/chatgpt/web/src/components/toaster/toast.tsx
import type { SvgIcon, ToastLevel } from "./types";

import "./toast.css";

const ALERT_TO_ICON = {
  success: CheckCircleIcon,
  warning: AlertIcon,
  danger: XCircleFilledIcon,
} as { [key in ToastLevel]?: SvgIcon };

export function Toast({
  zIndex,
  duration,
  onRemove,
  level,
  title,
  description,
  hasCloseButton,
  isShown: propIsShown = true,
  testId,
}: {
  zIndex?: number;
  duration?: number;
  onRemove?: () => void;
  level: ToastLevel;
  title: React.ReactNode;
  description?: React.ReactNode;
  hasCloseButton: boolean;
  isShown?: boolean;
  testId?: string;
}): React.ReactElement | null {
  const [isShown, setIsShown] = useState(propIsShown);
  const closeTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const close = useCallback((): void => {
    setIsShown(false);
  }, []);

  const startCloseTimer = useCallback((): void => {
    if (duration) {
      closeTimer.current = setTimeout(() => {
        close();
      }, duration * 1000);
    }
  }, [close, duration]);

  const clearCloseTimer = (): void => {
    if (closeTimer.current) {
      clearTimeout(closeTimer.current);
      closeTimer.current = null;
    }
  };

  useEffect(() => {
    if (isShown) {
      startCloseTimer();
    }
    return clearCloseTimer;
  }, [isShown, startCloseTimer]);

  useEffect(() => {
    if (!isShown) {
      onRemove?.();
    }
  }, [isShown, onRemove]);

  if (!isShown) {
    return null;
  }

  const Icon = ALERT_TO_ICON[level];

  return (
    <div className="toast-root no-drag" style={{ zIndex }}>
      <div className="no-drag w-full p-1 text-center md:w-auto md:text-justify">
        <Alert
          icon={Icon}
          level={level}
          onRemove={hasCloseButton ? close : undefined}
          testId={testId}
        >
          <div
            className={clsx("whitespace-pre-wrap text-start", {
              "font-medium": description,
            })}
          >
            {title}
          </div>
          {description ? <div className="text-start">{description}</div> : null}
        </Alert>
      </div>
    </div>
  );
}
