// https://github.com/openai/openai/blob/master/chatgpt/web/src/components/toaster/toaster-impl.ts
import type React from "react";

import type { ToastLevel } from "./types";

interface ToastSettings {
  id: string;
  description?: React.ReactNode;
  hasCloseButton?: boolean;
  // In seconds
  duration?: number;
  level?: ToastLevel;
  onRemove?: () => void;
  testId?: string;
}

interface ToastInstance {
  id: string | number;
  title: React.ReactNode;
  description?: React.ReactNode;
  hasCloseButton: boolean;
  duration: number;
  close: () => void;
  level: ToastLevel;
  isShown: boolean;
  onRemove?: () => void;
  testId?: string;
}

const hasCustomId = (
  settings: Partial<ToastSettings>,
): settings is ToastSettings => Object.hasOwnProperty.call(settings, "id");

let nextToastId = 0;

export interface Toaster {
  info(title: React.ReactNode, settings?: Partial<ToastSettings>): void;
  success(title: React.ReactNode, settings?: Partial<ToastSettings>): void;
  warning(title: React.ReactNode, settings?: Partial<ToastSettings>): void;
  danger(title: React.ReactNode, settings?: Partial<ToastSettings>): void;

  closeAll(): void;
}

export class ToasterImpl implements Toaster {
  toasts: ReadonlyArray<ToastInstance> = [];

  listeners = new Set<() => void>();

  subscribe = (onStoreChange: () => void): (() => void) => {
    this.listeners.add(onStoreChange);
    return () => this.listeners.delete(onStoreChange);
  };

  toastsChanged(): void {
    this.listeners.forEach((listener) => listener());
  }

  notify(
    title: React.ReactNode,
    settings: Partial<Pick<ToastSettings, "id">> & Omit<ToastSettings, "id">,
  ): ToastInstance {
    // If there's a custom toast ID passed, close existing toasts with the same custom ID
    if (hasCustomId(settings)) {
      for (const toast of this.toasts) {
        // Since unique ID is still appended to a custom ID, skip the unique ID and check only prefix
        if (String(toast.id).startsWith(settings.id)) {
          this.closeToast(toast.id);
        }
      }
    }

    const instance = this.createToastInstance(title, settings);

    this.toasts = [instance, ...this.toasts];
    this.toastsChanged();

    return instance;
  }

  createToastInstance(
    title: React.ReactNode,
    settings: Partial<Pick<ToastSettings, "id">> & Omit<ToastSettings, "id">,
  ): ToastInstance {
    const uniqueId = ++nextToastId;
    const id = hasCustomId(settings) ? `${settings.id}-${uniqueId}` : uniqueId;

    return {
      id,
      title,
      description: settings.description,
      hasCloseButton:
        typeof settings.hasCloseButton === "boolean"
          ? settings.hasCloseButton
          : true,
      duration: typeof settings.duration === "number" ? settings.duration : 5,
      close: () => this.closeToast(id),
      onRemove: settings.onRemove,
      level: settings.level ?? "info",
      isShown: true,
      testId: settings.testId,
    };
  }

  getToasts(): ReadonlyArray<ToastInstance> {
    return this.toasts;
  }

  closeToast(id: string | number): void {
    this.toasts = this.toasts.map((toast) => {
      if (toast.id === id) {
        return {
          ...toast,
          isShown: false,
        };
      }

      return toast;
    });
    this.toastsChanged();
  }

  removeToast(id: string | number): void {
    this.toasts.find((toast) => toast.id === id)?.onRemove?.();
    this.toasts = this.toasts.filter((toast) => toast.id !== id);
    this.toastsChanged();
  }

  closeAll(): void {
    this.toasts.forEach((toast) => toast.close());
  }

  info(
    title: React.ReactNode,
    settings?: Partial<ToastSettings>,
  ): ToastInstance {
    return this.notify(title, {
      ...settings,
      level: "info",
    });
  }

  success(
    title: React.ReactNode,
    settings?: Partial<ToastSettings>,
  ): ToastInstance {
    return this.notify(title, {
      ...settings,
      level: "success",
    });
  }

  warning(
    title: React.ReactNode,
    settings?: Partial<ToastSettings>,
  ): ToastInstance {
    return this.notify(title, {
      ...settings,
      level: "warning",
    });
  }

  danger(
    title: React.ReactNode,
    settings?: Partial<ToastSettings>,
  ): ToastInstance {
    return this.notify(title, {
      ...settings,
      level: "danger",
    });
  }
}

let firstToaster: ToasterImpl | null = null;
let pendingFirstToasterActions: Array<(toaster: Toaster) => void> = [];
let pendingFlushId: number | null = null;

export function setFirstToaster(toaster: ToasterImpl): void {
  firstToaster = toaster;
  if (pendingFlushId != null) {
    window.clearTimeout(pendingFlushId);
  }
  pendingFlushId = window.setTimeout(() => {
    pendingFlushId = null;
    if (firstToaster !== toaster) {
      return;
    }
    if (pendingFirstToasterActions.length === 0) {
      return;
    }
    const pending = pendingFirstToasterActions;
    pendingFirstToasterActions = [];
    pending.forEach((action) => action(toaster));
  }, 0);
}

export function clearFirstToaster(toaster: ToasterImpl): void {
  if (firstToaster === toaster) {
    firstToaster = null;
  }
}

export function getFirstToaster(): Toaster | null {
  return firstToaster;
}

export function withFirstToaster(action: (toaster: Toaster) => void): void {
  if (firstToaster) {
    action(firstToaster);
    return;
  }
  pendingFirstToasterActions.push(action);
}
